export default function GenevaLive({ onBack }) {
  const CYAN = "#00f5ff"
  const GREEN = "#22c55e"

  const cameras = [
    {
      id: "riviera",
      label: "CAM-A / RIVIERA DOCKS — CRUISE LINE",
      coords: "42.5847°N 88.4334°W — LAKE SHORE",
      desc: "Geneva Lake Cruise Line dock. Pre-Collapse resort infrastructure. Lake visible from Carrie Webb's cabin sector, bearing 312°.",
      embed: "https://g1.ipcamlive.com/player/player.php?alias=631a11e3d3293&autoplay=true",
      year: "2026"
    },
    {
      id: "grandgeneva",
      label: "CAM-B / GRAND GENEVA RESORT — SOUTH VIEW",
      coords: "42.5712°N 88.3891°W — MOUNTAIN TOP",
      desc: "Resort surveillance. High ground southwest of lake. Clear line of sight toward settlement coordinates. Pre-Collapse luxury infrastructure.",
      embed: "https://g1.ipcamlive.com/player/player.php?alias=5aea0a2674e5d&autoplay=true",
      year: "2026"
    },
    {
      id: "yachtclub",
      label: "CAM-C / LAKE GENEVA YACHT CLUB",
      coords: "42.5901°N 88.4289°W — NORTH SHORE",
      desc: "North shore surveillance. Direct view of lake surface and surrounding woodland. Settlement sector begins 4km northwest of this position.",
      embed: "https://www.ipcamlive.com/5b1a9a31a1f64",
      year: "2026"
    }
  ]

  return (
    <div style={{ maxWidth: 760, margin: "0 auto", padding: "20px" }}>
      {/* Back */}
      <div onClick={onBack} style={{ fontSize: 11, color: CYAN, cursor: "pointer", marginBottom: 16, letterSpacing: 2 }}>
        ← BACK TO ARCHIVE
      </div>

      {/* Header */}
      <div style={{
        background: "rgba(0,245,255,0.04)",
        border: `1px solid rgba(0,245,255,0.15)`,
        padding: "12px 16px",
        marginBottom: 16,
        display: "flex",
        alignItems: "center",
        justifyContent: "space-between"
      }}>
        <div>
          <div style={{ fontSize: 11, color: CYAN, letterSpacing: 3, fontFamily: "monospace" }}>
            ● LIVE — GENEVA LAKE SURVEILLANCE NETWORK
          </div>
          <div style={{ fontSize: 9, color: "#405060", fontFamily: "monospace", marginTop: 4 }}>
            WALWORTH COUNTY, WISCONSIN — 42.5847°N 88.4334°W — {new Date().getFullYear()} CE
          </div>
        </div>
        <div style={{ textAlign: "right" }}>
          <div style={{ fontSize: 9, color: "#405060", fontFamily: "monospace" }}>SECTOR: GL-7B NORTH SHORE</div>
          <div style={{ fontSize: 9, color: "rgba(239,68,68,0.7)", fontFamily: "monospace", marginTop: 2 }}>
            ⚠ PRE-COLLAPSE FOOTAGE
          </div>
        </div>
      </div>

      {/* Note */}
      <div style={{
        background: "rgba(0,245,255,0.05)",
        border: "1px solid rgba(0,245,255,0.15)",
        padding: "8px 12px",
        marginBottom: 16,
        fontFamily: "monospace",
        fontSize: 10,
        color: "rgba(0,245,255,0.7)",
        letterSpacing: 1
      }}>
        ARCHIVE NOTE: Geneva Lake, Wisconsin — 847.3 MHz signal detected from this sector intermittently
        since 2131. Source unconfirmed. C.L.A.W. signature consistent with northwest bearing from Chicago
        inner sectors. These feeds originate from 2026 CE. The lake shown here is the same lake.
        The cabin is not visible from any of these positions.
      </div>

      {/* Cameras */}
      {cameras.map((cam, idx) => (
        <div key={cam.id} style={{
          marginBottom: 20,
          background: "#000",
          border: `1px solid rgba(0,245,255,0.15)`,
          overflow: "hidden"
        }}>
          {/* Cam header */}
          <div style={{
            background: "rgba(0,245,255,0.06)",
            borderBottom: "1px solid rgba(0,245,255,0.1)",
            padding: "6px 12px",
            display: "flex",
            alignItems: "center",
            justifyContent: "space-between"
          }}>
            <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
              <div style={{
                width: 7, height: 7, borderRadius: "50%",
                background: GREEN,
                boxShadow: `0 0 6px ${GREEN}`,
                animation: "pulse 1.2s infinite"
              }} />
              <span style={{ fontSize: 10, color: GREEN, letterSpacing: 2, fontFamily: "monospace" }}>● LIVE</span>
            </div>
            <span style={{ fontSize: 9, color: CYAN, letterSpacing: 2, fontFamily: "monospace" }}>{cam.label}</span>
            <span style={{ fontSize: 9, color: "#405060", fontFamily: "monospace" }}>{cam.coords}</span>
          </div>

          {/* Video with CSS cyberpunk overlay */}
          <div style={{ position: "relative", paddingBottom: "56.25%", height: 0 }}>
            <iframe
              title={cam.label}
              src={cam.embed}
              style={{
                position: "absolute", top: 0, left: 0,
                width: "100%", height: "100%",
                border: "none",
                filter: "saturate(0.3) hue-rotate(180deg) brightness(0.8) contrast(1.1)"
              }}
              allow="autoplay; encrypted-media"
              allowFullScreen
            />
            {/* Scanlines */}
            <div style={{
              position: "absolute", inset: 0,
              background: "repeating-linear-gradient(0deg, transparent, transparent 3px, rgba(0,0,0,0.12) 3px, rgba(0,0,0,0.12) 4px)",
              pointerEvents: "none", zIndex: 10
            }} />
            {/* Cyan tint */}
            <div style={{
              position: "absolute", inset: 0,
              background: "rgba(0,245,255,0.03)",
              pointerEvents: "none", zIndex: 9
            }} />
            {/* Corner overlays */}
            <div style={{
              position: "absolute", top: 8, left: 8,
              fontSize: 8, color: "rgba(239,68,68,0.8)",
              fontFamily: "monospace", zIndex: 11,
              textShadow: "0 0 4px rgba(239,68,68,0.5)"
            }}>● REC</div>
            <div style={{
              position: "absolute", top: 8, right: 8,
              fontSize: 8, color: "rgba(0,245,255,0.7)",
              fontFamily: "monospace", zIndex: 11
            }}>{cam.year} CE</div>
            <div style={{
              position: "absolute", bottom: 8, left: 8,
              fontSize: 7, color: "rgba(0,245,255,0.5)",
              fontFamily: "monospace", zIndex: 11
            }}>{cam.coords}</div>
          </div>

          {/* Cam footer */}
          <div style={{
            padding: "8px 12px",
            borderTop: "1px solid rgba(0,245,255,0.08)",
            background: "rgba(0,0,0,0.5)"
          }}>
            <div style={{ fontSize: 10, color: "#6a8090", fontFamily: "monospace", letterSpacing: 1 }}>
              {cam.desc}
            </div>
          </div>
        </div>
      ))}

      <div style={{ fontSize: 9, color: "#405060", textAlign: "center", fontFamily: "monospace", letterSpacing: 1, marginTop: 8 }}>
        SIGNAL.tv — GENEVA LAKE SURVEILLANCE ARCHIVE — PRE-COLLAPSE DOCUMENTATION
      </div>

      <style>{`
        @keyframes pulse { 0%,100%{opacity:1} 50%{opacity:0.3} }
      `}</style>
    </div>
  )
}
